/**
 * LatentSpaceMap
 * ──────────────────────────────────────────────────────────────────────────────
 * Interactive 2D projection of the CVAE latent space.
 *
 * Requires public/latent_map.json generated by:
 *   python scripts/generate_map.py
 *
 * Interactions
 * ─────────────
 * • Hover   → patch name tooltip
 * • Click on a point  → decode its z_vector (or use stored params) → send NRPNs
 * • Click in empty space → KNN (k=5) IDW interpolation of surrounding
 *   z_vectors or param-vectors → decode → send NRPNs
 * • Crosshair  → shows the position of the current patch in the map
 *   (nearest neighbour by Euclidean distance on the 37-dim param vector)
 * • Category filter buttons → highlight / isolate a sound category
 */

import {
  useState, useEffect, useRef, useMemo, useCallback,
} from 'react';
import styled from 'styled-components';
import { useCurrentPatch } from '../stores/patchStore';
import { useMidiStore } from '../midi/usePreenFM3Midi';
import { patchToNRPNMessages } from '../midi/patchSerializer';
import { sendNRPN, clearNRPNQueue, drainNRPNQueue } from '../midi/midiService';
import {
  variator,
  patchToParamVector,
  paramVectorToPatch,
  enforceValidity,
  Z_OSC_DIM,
  Z_ENV_DIM,
  Z_MATRIX_DIM,
} from '../ml/patchVariator';
import type { Patch } from '../types/patch';

// ── Constants ──────────────────────────────────────────────────────────────────

const CATEGORY_COLORS: Record<string, string> = {
  BASS:  '#3b82f6',
  LEAD:  '#ef4444',
  PAD:   '#8b5cf6',
  PERC:  '#f59e0b',
  PLUCK: '#10b981',
  SFX:   '#6b7280',
};

const KNN_K      = 5;    // neighbours for IDW interpolation
const HIT_PX     = 14;   // pixel radius to detect a direct point click
const PARAM_DIM  = 37;   // FM parameter vector length used for crosshair distance
const CANVAS_PAD = 24;   // padding between canvas edge and the point cloud

// ── Types ──────────────────────────────────────────────────────────────────────

interface MapPoint {
  name:     string;
  x:        number;       // normalised [0, 1]
  y:        number;
  z_vector: number[];     // 12-dim; empty when has_z_vectors=false
  params:   number[];     // 85-dim  — always present (37-dim in legacy JSON)
  category: string;
  // Structured-head coordinates (present when mapData.structured === true)
  x_timbre?:    number; y_timbre?:    number;
  x_dynamics?:  number; y_dynamics?:  number;
  x_modulation?: number; y_modulation?: number;
}

interface MapData {
  has_z_vectors: boolean;
  latent_dim:    number;
  method:        string;
  points:        MapPoint[];
  // Structured latent space (3-head CVAE)
  structured?:   boolean;
  z_osc_dim?:    number;
  z_env_dim?:    number;
  z_matrix_dim?: number;
}

